#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <float.h>
#include <CL/cl.h>

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

// Inline kernel source
const char *kernel_source = 
"__inline float euclid_dist_2(float *pt1, float *pt2, int numdims) { "
"    float ans = 0.0f; "
"    for (int i = 0; i < numdims; i++) { "
"        float diff = pt1[i] - pt2[i]; "
"        ans += diff * diff; "
"    } "
"    return ans; "
"} "
"__inline int find_nearest_point(float *pt, int nfeatures, float *clusters, int nclusters) { "
"    int index = 0; "
"    float min_dist = FLT_MAX; "
"    for (int i = 0; i < nclusters; i++) { "
"        float dist = euclid_dist_2(pt, clusters + i * nfeatures, nfeatures); "
"        if (dist < min_dist) { "
"            min_dist = dist; "
"            index = i; "
"        } "
"    } "
"    return index; "
"} "
"void kmeans_step( "
"    const int npoints, "
"    const int nfeatures, "
"    const int nclusters, "
"    const float *feature_data, "
"    float *cluster_data, "
"    int *membership, "
"    int *partial_counts, "
"    float *partial_centers, "
"    float *delta_vals) "
"{ "
"    int tid = get_global_id(0); "
"    if (tid >= npoints) return; "
"    float *pt = feature_data + tid * nfeatures; "
"    int index = find_nearest_point(pt, nfeatures, cluster_data, nclusters); "
"    float delta = 0.0f; "
"    if (membership[tid] != index) delta = 1.0f; "
"    membership[tid] = index; "
"    delta_vals[tid] = delta; "
"    partial_counts[tid * nclusters + index] = 1; "
"    for (int j = 0; j < nfeatures; j++) { "
"        partial_centers[tid * nclusters * nfeatures + index * nfeatures + j] = pt[j]; "
"    } "
"} "
"void kmeans_aggregate( "
"    const int npoints, "
"    const int nfeatures, "
"    const int nclusters, "
"    const int nthreads, "
"    int *partial_counts, "
"    float *partial_centers, "
"    float *cluster_data, "
"    int *cluster_counts) "
"{ "
"    int i = get_global_id(0); "
"    if (i >= nclusters) return; "
"    float sum_val = 0.0f; "
"    int count = 0; "
"    for (int t = 0; t < nthreads; t++) { "
"        int c = partial_counts[t * nclusters + i]; "
"        count += c; "
"        if (c > 0) { "
"            for (int k = 0; k < nfeatures; k++) { "
"                sum_val += partial_centers[(t * nclusters + i) * nfeatures + k]; "
"            } "
"        } "
"    } "
"    cluster_counts[i] = count; "
"    if (count > 0) { "
"        for (int k = 0; k < nfeatures; k++) { "
"            cluster_data[i * nfeatures + k] = sum_val / count; "
"        } "
"    } "
"} ";

float euclid_dist_2_host(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

int find_nearest_point_host(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;
    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2_host(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

float **kmeans_clustering(float **feature, int nfeatures, int npoints, int nclusters, float threshold, int *membership) {
    cl_platform_id platform;
    cl_device_id device;
    cl_context context;
    cl_command_queue queue;
    cl_program program;
    cl_kernel kernel_step, kernel_agg;

    cl_uint num_platforms, num_devices;
    if (clGetPlatformIDs(1, &platform, &num_platforms) != CL_SUCCESS || num_platforms == 0) {
        fprintf(stderr, "Failed to find platform\n");
        return NULL;
    }
    if (clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 1, &device, &num_devices) != CL_SUCCESS || num_devices == 0) {
        fprintf(stderr, "Failed to find device\n");
        return NULL;
    }

    context = clCreateContext(NULL, 1, &device, NULL, NULL, NULL);
    queue = clCreateCommandQueue(context, device, 0, NULL);

    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, NULL);
    if (clBuildProgram(program, 1, &device, NULL, NULL, NULL) != CL_SUCCESS) {
        fprintf(stderr, "Failed to build program\n");
        return NULL;
    }

    kernel_step = clCreateKernel(program, "kmeans_step", NULL);
    kernel_agg = clCreateKernel(program, "kmeans_aggregate", NULL);

    size_t feat_size = (size_t)npoints * nfeatures * sizeof(float);
    size_t clust_size = (size_t)nclusters * nfeatures * sizeof(float);
    size_t mem_size = npoints * sizeof(int);
    size_t partial_counts_size = (size_t)npoints * nclusters * sizeof(int);
    size_t partial_centers_size = (size_t)npoints * nclusters * nfeatures * sizeof(float);
    size_t delta_size = npoints * sizeof(float);
    size_t cluster_counts_size = nclusters * sizeof(int);

    cl_mem d_feature = clCreateBuffer(context, CL_MEM_READ_ONLY, feat_size, NULL, NULL);
    cl_mem d_clusters = clCreateBuffer(context, CL_MEM_READ_WRITE, clust_size, NULL, NULL);
    cl_mem d_membership = clCreateBuffer(context, CL_MEM_READ_WRITE, mem_size, NULL, NULL);
    cl_mem d_partial_counts = clCreateBuffer(context, CL_MEM_READ_WRITE, partial_counts_size, NULL, NULL);
    cl_mem d_partial_centers = clCreateBuffer(context, CL_MEM_READ_WRITE, partial_centers_size, NULL, NULL);
    cl_mem d_delta = clCreateBuffer(context, CL_MEM_READ_WRITE, delta_size, NULL, NULL);
    cl_mem d_cluster_counts = clCreateBuffer(context, CL_MEM_READ_WRITE, cluster_counts_size, NULL, NULL);

    float *feat_flat = feature[0];
    clEnqueueWriteBuffer(queue, d_feature, CL_TRUE, 0, feat_size, feat_flat, 0, NULL, NULL);

    float *init_clusters = malloc(clust_size);
    for (int i = 0; i < nclusters; i++) {
        for (int j = 0; j < nfeatures; j++) {
            init_clusters[i * nfeatures + j] = feature[i][j];
        }
    }
    clEnqueueWriteBuffer(queue, d_clusters, CL_TRUE, 0, clust_size, init_clusters, 0, NULL, NULL);
    free(init_clusters);

    clEnqueueWriteBuffer(queue, d_membership, CL_TRUE, 0, mem_size, membership, 0, NULL, NULL);

    int loop = 0;
    float delta = 0.0;
    int nthreads = npoints; 

    do {
        delta = 0.0;
        int zero = 0;
        clEnqueueFillBuffer(queue, d_partial_counts, &zero, sizeof(int), partial_counts_size, 0, NULL, NULL);
        clEnqueueFillBuffer(queue, d_partial_centers, &zero, sizeof(float), partial_centers_size, 0, NULL, NULL);

        clSetKernelArg(kernel_step, 0, sizeof(int), &npoints);
        clSetKernelArg(kernel_step, 1, sizeof(int), &nfeatures);
        clSetKernelArg(kernel_step, 2, sizeof(int), &nclusters);
        clSetKernelArg(kernel_step, 3, sizeof(cl_mem), &d_feature);
        clSetKernelArg(kernel_step, 4, sizeof(cl_mem), &d_clusters);
        clSetKernelArg(kernel_step, 5, sizeof(cl_mem), &d_membership);
        clSetKernelArg(kernel_step, 6, sizeof(cl_mem), &d_partial_counts);
        clSetKernelArg(kernel_step, 7, sizeof(cl_mem), &d_partial_centers);
        clSetKernelArg(kernel_step, 8, sizeof(cl_mem), &d_delta);

        size_t global_step = npoints;
        if (clEnqueueTask(queue, kernel_step, 1, NULL, &global_step, NULL, 0, NULL, NULL) != CL_SUCCESS) {
            fprintf(stderr, "Failed to enqueue step kernel\n");
            break;
        }

        clSetKernelArg(kernel_agg, 0, sizeof(int), &npoints);
        clSetKernelArg(kernel_agg, 1, sizeof(int), &nfeatures);
        clSetKernelArg(kernel_agg, 2, sizeof(int), &nclusters);
        clSetKernelArg(kernel_agg, 3, sizeof(int), &nthreads);
        clSetKernelArg(kernel_agg, 4, sizeof(cl_mem), &d_partial_counts);
        clSetKernelArg(kernel_agg, 5, sizeof(cl_mem), &d_partial_centers);
        clSetKernelArg(kernel_agg, 6, sizeof(cl_mem), &d_clusters);
        clSetKernelArg(kernel_agg, 7, sizeof(cl_mem), &d_cluster_counts);

        size_t global_agg = nclusters;
        if (clEnqueueTask(queue, kernel_agg, 1, NULL, &global_agg, NULL, 0, NULL, NULL) != CL_SUCCESS) {
            fprintf(stderr, "Failed to enqueue aggregate kernel\n");
            break;
        }

        clFinish(queue);

        float *host_delta = malloc(delta_size);
        clEnqueueReadBuffer(queue, d_delta, CL_TRUE, 0, delta_size, host_delta, 0, NULL, NULL);
        for (int i = 0; i < npoints; i++) delta += host_delta[i];
        free(host_delta);

        loop++;
    } while (delta > threshold && loop < 500);

    float *final_clusters = malloc(clust_size);
    clEnqueueReadBuffer(queue, d_clusters, CL_TRUE, 0, clust_size, final_clusters, 0, NULL, NULL);

    float **clusters = malloc(nclusters * sizeof(float*));
    clusters[0] = final_clusters;
    for (int i = 1; i < nclusters; i++) clusters[i] = clusters[i-1] + nfeatures;

    clReleaseMemObject(d_feature);
    clReleaseMemObject(d_clusters);
    clReleaseMemObject(d_membership);
    clReleaseMemObject(d_partial_counts);
    clReleaseMemObject(d_partial_centers);
    clReleaseMemObject(d_delta);
    clReleaseMemObject(d_cluster_counts);
    clReleaseKernel(kernel_step);
    clReleaseKernel(kernel_agg);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);

    return clusters;
}

int cluster(int numObjects, int numAttributes, float **attributes, int nclusters, float threshold, float ***cluster_centres) {
    int *membership = malloc(numObjects * sizeof(int));
    srand(7);
    float **tmp = kmeans_clustering(attributes, numAttributes, numObjects, nclusters, threshold, membership);
    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp;
    free(membership);
    return 0;
}

int main(int argc, char **argv) {
    char *filename = NULL;
    int nclusters = 5;
    float threshold = 0.001;
    int isBinaryFile = 0;
    int numAttributes, numObjects;
    float *buf;
    float **attributes;
    float **cluster_centres = NULL;

    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "-i") == 0 && i+1 < argc) filename = argv[++i];
        else if (strcmp(argv[i], "-k") == 0 && i+1 < argc) nclusters = atoi(argv[++i]);
        else if (strcmp(argv[i], "-t") == 0 && i+1 < argc) threshold = atof(argv[++i]);
        else if (strcmp(argv[i], "-b") == 0) isBinaryFile = 1;
    }

    if (!filename) {
        fprintf(stderr, "Usage: %s -i filename\n", argv[0]);
        return -1;
    }

    FILE *infile = fopen(filename, "r");
    if (!infile) {
        fprintf(stderr, "Error: no such file (%s)\n", filename);
        return 1;
    }

    char line[1024];
    numObjects = 0;
    while (fgets(line, sizeof(line), infile)) {
        if (strtok(line, " \t\n")) numObjects++;
    }
    rewind(infile);
    numAttributes = 0;
    while (fgets(line, sizeof(line), infile)) {
        if (strtok(line, " \t\n")) {
            char *tok = strtok(NULL, " ,\t\n");
            while (tok) { numAttributes++; tok = strtok(NULL, " ,\t\n"); }
            break;
        }
    }
    rewind(infile);

    buf = malloc(numObjects * numAttributes * sizeof(float));
    attributes = malloc(numObjects * sizeof(float*));
    attributes[0] = buf;
    for (int i = 1; i < numObjects; i++) attributes[i] = attributes[i-1] + numAttributes;

    int idx = 0;
    while (fgets(line, sizeof(line), infile)) {
        if (!strtok(line, " \t\n")) continue;
        for (int j = 0; j < numAttributes; j++) {
            char *tok = strtok(NULL, " ,\t\n");
            if (tok) buf[idx++] = atof(tok);
        }
    }
    fclose(infile);

    printf("I/O completed\n");

    cluster(numObjects, numAttributes, attributes, nclusters, threshold, &cluster_centres);

    printf("number of Clusters %d\n", nclusters);
    printf("number of Attributes %d\n\n", numAttributes);
    printf("Time for process: %f\n", 0.0);

    free(attributes);
    free(cluster_centres[0]);
    free(cluster_centres);
    free(buf);

    return 0;
}
